#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return *(char*)a - *(char*)b;
}

int factorial(int n) {
    int result = 1;
    for (int i = 2; i <= n; i++) {
        result *= i;
    }
    return result;
}

int findRank(char *str) {
    int len = strlen(str);
    int rank = 1;
    int *freq = (int*)calloc(10, sizeof(int));
    for (int i = 0; i < len; i++) {
        freq[str[i] - '0']++;
    }
    int *fact = (int*)malloc(len * sizeof(int));
    fact[0] = 1;
    for (int i = 1; i < len; i++) {
        fact[i] = fact[i - 1] * i;
    }
    for (int i = 0; i < len - 1; i++) {
        int count = 0;
        for (int j = 0; j < str[i] - '0'; j++) {
            if (freq[j] > 0) {
                count += fact[len - i - 1] * freq[j];
            }
        }
        rank += count;
        freq[str[i] - '0']--;
    }
    free(fact);
    free(freq);
    return rank;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char str[19];
        scanf("%s", str);
        printf("%d\n", findRank(str));
    }
    return 0;
}

