import math

def findRank(s):
    n = len(s)
    rank = 1
    freq = [0] * 10
    for i in range(n):
        freq[int(s[i])] += 1
    fact = [math.factorial(i) for i in range(18)]
    for i in range(n - 1):
        count = 0
        for j in range(int(s[i])):
            if freq[j] > 0:
                count += fact[n - i - 1] * freq[j]
        rank += count
        freq[int(s[i])] -= 1
    return rank

